class Solution:

def solve(self, matrix: List[List[int]]) -> bool:
  n = len(matrix)
  cnt = [[0]*n for _ in range(2)]
  for i in range(n):
    for j in range(n):
      cnt[matrix[i][j] & 1][j] += 1
  for i in range(n):
    if cnt[1][i] > cnt[0][i]:
      return False
  res = [[0]*n for _ in range(n)]
  def dfs(row, col):
    if row == n:
      return True
    if res[row][col] != -1:
      return False
    res[row][col] = 0
    if dfs(row+1, col):
      return True
    res[row][col] = 1
    if dfs(row+1, col):
      return True
    return False
  for i in range(n):
    for j in range(n):
      res[i][j] = -1
  if not dfs(0, 0):
    return False
  return True


if __name__ == '__main__':
  s = Solution()
  matrix = [[1, 0, 1], [0, 0, 0], [1, 1, 1]]
  print(s.solve(matrix))

