class Solution {
public:
bool solve(vector<vector<int>>& matrix) {
  int n = matrix.size();
  int cnt[2][n] = {{0}};
  for (int i = 0; i < n; i++)
    for (int j = 0; j < n; j++)
      cnt[matrix[i][j] & 1][j]++;
  for (int i = 0; i < n; i++)
    if (cnt[1][i] > cnt[0][i])
      return false;
  vector<vector<int>> res(n, vector<int>(n));
  void dfs(int row, int col) {
    if (row == n) return;
    if (res[row][col] != -1) return;
    res[row][col] = 0;
    if (dfs(row+1, col)) return;
    res[row][col] = 1;
    if (dfs(row+1, col)) return;
    return;
  }
  for (int i = 0; i < n; i++)
    for (int j = 0; j < n; j++)
      res[i][j] = -1;
  if (!dfs(0, 0)) return false;
  for (int i = 0; i < n; i++)
    for (int j = 0; j < n; j++)
      matrix[i][j] = res[i][j];
  return true;
}
};
